/* 书签系统第一批 · harness 专用假书数据 + pywebview API stub。
   只服务本 spec 的验收测试，不是产品代码。 */
(function(){
  const SENTS = [
    'In order to retrieve creativity, we need to find it.',
    'I ask you to do this by an apparently pointless process I call the morning pages.',
    'There is no wrong way to do morning pages.',
    'These daily meanderings are not meant to be art, or even writing.',
    'Pages are meant to be, simply, the act of moving the hand across the page.',
    'Nobody is allowed to read your morning pages except you.',
    'Anger is fuel, we feel it and we want to do something.',
    'Hit someone, break something, throw a fit, smash a fist into the wall.',
    'But we are nice people, and what we do with our anger is stuff it, deny it, bury it.',
    'Anger is meant to be listened to, a voice, a shout, a plea, a demand.',
    'Creativity flourishes when we have a sense of safety and self acceptance.',
    'Your artist, like a small child, is happiest when feeling a sense of security.',
    'As our artist protective parent, we must learn to place our artist with safe companions.',
    'The reward for attention is always healing, it may begin as the healing of a particular pain.',
    'This great life, this attentive life, is available to all of us, every day.',
    'More than anything else, attention is an act of connection between reader and page.'
  ];
  let _seed = 42;
  function rnd(){ _seed = (_seed*1103515245+12345) & 0x7fffffff; return _seed/0x7fffffff; }
  function pick(){ return SENTS[Math.floor(rnd()*SENTS.length)]; }
  // 把每个英文词包成 <span class="w">——真实正文（reader_core/render.py）就是这么渲染的，
  // 高亮/划选的 liftRangeToWords 会吸附到这些词边界。canned 若用纯文本会掩盖"选区边界落
  // 在元素节点"这类 bug（书模式高亮锚点丢失就是这么漏过的），故这里保持与真实 DOM 一致。
  function wrapW(text){
    return text.replace(/[A-Za-z]+(?:['’\-][A-Za-z]+)*/g, m=>`<span class="w">${m}</span>`);
  }
  function para(n, withVocab){
    let s = [];
    for(let i=0;i<n;i++) s.push(pick());
    let html = wrapW(s.join(' '));
    if(withVocab){
      // 插一个 mark.vocab 供「点词不产生书签」测试（固定塞一句含 meanderings 的句子，不依赖随机采样命中）
      html = '<mark class="vocab" data-word="meanderings" data-lemma="meandering" data-freq="common">Meanderings</mark> '+wrapW('are not meant to be art.')+' ' + html;
    }
    return '<p>'+html+'</p>';
  }
  function chapterHtml(nParas, vocabParaIdx){
    let out='';
    for(let i=0;i<nParas;i++) out += para(6+Math.floor(rnd()*3), i===vocabParaIdx);
    return out;
  }

  // chars=本章字数（后端 _toc_list 现随每章带来）——供前端估算全局页码。这里各章长度不同，
  // 好验证「全局页码 = 前面各章估算页 + 本章当前页」不是章内页码。
  const CH_PARAS = [12, 22, 8];   // 各章段数（对应 chars 约 380/段）
  const TOC = [
    {idx:0, title:'The Morning Pages',   chars: CH_PARAS[0]*380},
    {idx:1, title:'Anger and Attention', chars: CH_PARAS[1]*380},
    {idx:2, title:'The Artist Child',    chars: CH_PARAS[2]*380}
  ];
  const CHAPTERS = TOC.map((t,i)=>({
    chapter_idx:i,
    article_html: chapterHtml(CH_PARAS[i], 2),
    vocab_list: [],
    total_tokens: 800,
    vocab_count: 1,
    vocab_order_count: 0
  }));

  let SAVED_RECORD = null;   // 模拟 library/{id}.json，用于 save_session/load_archive 闭环

  window.__BK_HARNESS__ = { TOC, CHAPTERS, get record(){ return SAVED_RECORD; } };

  /* 首页第三批 · 假 list_library：2 本书（1 本有进度=hero、1 本未开卷）+ 4 篇文章（含 1 篇无摘要），
     供 harness 静态服务器渲染出真实首页布局（书墙 hero+小封面、剪报盒横向卡）供截图验收。 */
  const HOME_BOOKS = [
    { id:'home-book-1', mode:'book', title:"The Artist's Way", source:'Julia Cameron',
      saved_at: Date.now()/1000 - 3600, current_chapter:1, chapter_count: TOC.length, cover:'data:image/jpeg;base64,' },
    { id:'home-book-2', mode:'book', title:'To Kill a Mockingbird', source:'Harper Lee',
      saved_at: Date.now()/1000 - 86400*3, current_chapter:0, chapter_count: TOC.length },
    { id:'home-book-3', mode:'book', title:'The Body Keeps the Score', source:'Bessel van der Kolk',
      saved_at: Date.now()/1000 - 86400*5, current_chapter:8, chapter_count: 20 },
    { id:'home-book-4', mode:'book', title:'Bossypants', source:'Tina Fey',
      saved_at: Date.now()/1000 - 86400*7, current_chapter:0, chapter_count: 15, cover:'data:image/jpeg;base64,' },
    { id:'home-book-5', mode:'book', title:'On Writing', source:'Stephen King',
      saved_at: Date.now()/1000 - 86400*9, current_chapter:3, chapter_count: 12 },
    { id:'home-book-6', mode:'book', title:'Walden', source:'Henry David Thoreau',
      saved_at: Date.now()/1000 - 86400*11, current_chapter:2, chapter_count: 18 },
    { id:'home-book-7', mode:'book', title:'Meditations', source:'Marcus Aurelius',
      saved_at: Date.now()/1000 - 86400*13, current_chapter:5, chapter_count: 12 },
  ];
  const HOME_ARTICLES = [
    { id:'home-art-1', mode:'article', title:'Rural Escapism', source:'sixthtone.com',
      saved_at: Date.now()/1000 - 7200, excerpt:"Why China's young urbanites are romanticising country life — and what they find when they get there." },
    { id:'home-art-2', mode:'article', title:'The Morning Pages', source:'手动粘贴',
      saved_at: Date.now()/1000 - 43200, excerpt:'There is no wrong way to do morning pages. In order to retrieve creativity, we need to find it.' },
    { id:'home-art-3', mode:'article', title:"Anwar's coalition partners pledge to finish term", source:'channelnewsasia.com',
      saved_at: Date.now()/1000 - 172800, excerpt:"Malaysia's ruling bloc closed ranks despite recent defections and pressure over the economy." },
    { id:'home-art-4', mode:'article', title:'Pritam Singh holds on to party chief position', source:'straitstimes.com',
      saved_at: Date.now()/1000 - 259200 }, // 故意不给 excerpt，覆盖「无正文摘要」情况
  ];
  let HOME_ITEMS = [...HOME_BOOKS, ...HOME_ARTICLES];

  window.pywebview = { api: {
    async get_settings(){ return { llm_enabled:true }; },
    async process(args){
      if(args.source==='harness-article'){
        return {
          mode:'article', title:'A Short Essay (harness)', source:'harness-article',
          total_tokens: 900, vocab_count:1,
          article_html: chapterHtml(14, 2),
          vocab_list: [], vocab_order_count:0, llm_enabled:true,
        };
      }
      return {
        mode:'book', title:'The Artist’s Way (harness)', source:args.source,
        toc: TOC, chapter_idx:0, chapter_count: TOC.length,
        llm_enabled:true, ...CHAPTERS[0]
      };
    },
    async load_chapter(args){
      const idx = Math.max(0, Math.min(TOC.length-1, args.idx|0));
      return CHAPTERS[idx];
    },
    async save_session(args){
      SAVED_RECORD = { ...(SAVED_RECORD||{}), ...args, mode:'book', id:'harness-book' };
      return { ok:true, id:'harness-book' };
    },
    async load_archive(args){
      const id = (args||{}).id;
      // 首页书墙/剪报盒里点开的假条目：书给个 TOC[0]，文章给个假正文，验证 openArchive 闭环。
      const homeBook = HOME_BOOKS.find(b=>b.id===id);
      if(homeBook){
        return {
          ok:true, mode:'book', title:homeBook.title,
          toc: TOC, chapter_idx:0, chapter_count: TOC.length,
          current_page:0, theme:'indigo',
          bookmarks:[], highlights:[], dots:[], phrases:[], llm_enabled:true,
          ...CHAPTERS[0]
        };
      }
      const homeArt = HOME_ARTICLES.find(a=>a.id===id);
      if(homeArt){
        return {
          ok:true, mode:'article', title:homeArt.title, source:homeArt.source,
          article_html: chapterHtml(10, 1), theme:'indigo', llm_enabled:true,
          vocab_list: [], vocab_order_count:0,
        };
      }
      if(!SAVED_RECORD) return { error:'存档不存在' };
      const idx = Math.max(0, Math.min(TOC.length-1, SAVED_RECORD.chapter||0));
      return {
        ok:true, mode:'book', title:'The Artist’s Way (harness)',
        toc: TOC, chapter_idx: idx, chapter_count: TOC.length,
        current_page: SAVED_RECORD.page||0, theme: SAVED_RECORD.theme||'indigo',
        bookmarks: SAVED_RECORD.bookmarks||[], highlights: SAVED_RECORD.highlights||[], dots: SAVED_RECORD.dots||[],
        phrases: SAVED_RECORD.phrases||[], llm_enabled:true,
        ...CHAPTERS[idx]
      };
    },
    async list_library(){ return HOME_ITEMS; },
    async start_pregen(){ return {ok:true}; },
    async get_pregen_status(){ return {done:0,total:0,running:false}; },
    async explain_word(args){
      // ④ 测试用：返回带 lemma 的最小讲解形状，并把该 lemma 已完成的 followups(若有)带出，
      // 模拟后端 explain_word 4a 的行为（回看必复原的地基）。
      const lemma=((args&&(args.lemma||args.word))||'').trim().toLowerCase();
      window.__FOLLOWUPS = window.__FOLLOWUPS || {};
      const out={ ok:true, word:(args&&args.word)||'', lemma, explanation:'(harness) explanation for '+lemma, kind:'word' };
      if(window.__FOLLOWUPS[lemma] && window.__FOLLOWUPS[lemma].length) out.followups=window.__FOLLOWUPS[lemma].slice();
      return out;
    },
    async explain_selection(args){
      const text=((args&&args.text)||(args&&args.word)||'').trim();
      const lemma='§'+text.toLowerCase().split(/\s+/).join(' ');
      window.__FOLLOWUPS = window.__FOLLOWUPS || {};
      const out={ ok:true, text, word:text, lemma, meaning:'(harness) meaning for '+text, kind:'phrase' };
      if(window.__FOLLOWUPS[lemma] && window.__FOLLOWUPS[lemma].length) out.followups=window.__FOLLOWUPS[lemma].slice();
      return out;
    },
    async prewarm_word(){ return {}; },
    async get_audio(){ return {}; },
    async get_notebook(){ return []; },
    async get_global_notebook(){ return []; },
    async copy_text(){ return {ok:true}; },
    async export_csv(){ return {ok:true}; },
    async export_html(){ return {ok:true}; },
    async delete_archive(args){ HOME_ITEMS = HOME_ITEMS.filter(it=>it.id!==(args||{}).id); return {ok:true}; },
    async delete_global(){ return {ok:true}; },
    async set_known(){ return {ok:true}; },
    async set_star(){ return {ok:true}; },
    async save_settings(){ return {ok:true}; },
    async test_settings(){ return {ok:true}; },
    async read_clipboard(){ return {text:''}; },
    async process_file(){ return {}; },
    async ask_followup(args){
      // ④ 测试用可控延迟：window.__ASK_DELAY_MS 控制 resolve 延迟（默认 0）；
      // resolve 后模拟后端把答案写进 notebook.followups（供切回复原验证读取来源不依赖前端缓存）。
      const delay = (window.__ASK_DELAY_MS!=null) ? window.__ASK_DELAY_MS : 0;
      await new Promise(res=>setTimeout(res, delay));
      const word=(args&&args.word)||'', lemma=((args&&args.lemma)||word||'').trim().toLowerCase();
      const label=(args&&args.label)||(args&&args.question)||'';
      const answer='(harness) answer #'+((window.__askSeq=(window.__askSeq||0)+1))+' for '+word;
      window.__FOLLOWUPS = window.__FOLLOWUPS || {};
      window.__FOLLOWUPS[lemma] = window.__FOLLOWUPS[lemma] || [];
      window.__FOLLOWUPS[lemma].push({q:label, a:answer});
      return {ok:true, answer};
    },
    async collect_keyword(args){ window.__lastCollect=args; return {ok:true, key:'§'+((args&&args.word)||'').toLowerCase(), collected:true}; },
    async collect_paragraph(args){
      window.__lastCollectPara=args;
      const key='¶'+((args&&args.text)||'').toLowerCase().split(/\s+/).join(' ');
      window.__paraKeys = window.__paraKeys || new Set();
      const already = window.__paraKeys.has(key);
      window.__paraKeys.add(key);
      return {ok:true, key, collected:!already, already: already||undefined};
    },
    async fetch_feed(args){
      // ⑥ 测试用：真实网络请求(CORS 会挡真实 RSS 域，浏览器侧没法直接验)在 app.py 层
      // 已用 requests 单独验过(见施工日志，CNA/TC 各 20 条真实 200)；这里只验前端接线：
      // 渲染/展开/点文章跳转。canned 数据形状与真实 fetch_feed 输出完全一致。
      window.__lastFetchFeed=args;
      const url=(args&&args.url)||'';
      if(url.includes('channelnewsasia')){
        window.__fetchFeedCallCount=(window.__fetchFeedCallCount||0)+1;
        return {ok:true, items:[
          {title:'Ten-man England survive Mexico comeback to reach quarter-finals', url:'https://www.channelnewsasia.com/sport/a1', date:new Date(Date.now()-3600e3).toISOString(), summary:''},
          {title:'Singapore markets close higher amid tech rally', url:'https://www.channelnewsasia.com/business/a2', date:new Date(Date.now()-7200e3).toISOString(), summary:'Tech stocks led broad gains.'},
        ]};
      }
      if(url.includes('theconversation')){
        window.__fetchFeedCallCount=(window.__fetchFeedCallCount||0)+1;
        const uk=url.includes('/uk/'), us=url.includes('/us/');
        if(uk) return {ok:true, items:[
          {title:'The hidden grammar of birdsong, and what it shares with human language', url:'https://theconversation.com/uk-birdsong', date:new Date(Date.now()-39600e3).toISOString(), summary:'A linguist explains.'},
        ]};
        if(us) return {ok:true, items:[
          {title:'Why some memories fade and others last a lifetime', url:'https://theconversation.com/us-memories', date:new Date(Date.now()-25200e3).toISOString(), summary:'A neuroscientist explains.'},
        ]};
        return {ok:true, items:[
          {title:'What the science of awe tells us about everyday moments', url:'https://theconversation.com/global-awe', date:new Date(Date.now()-14400e3).toISOString(), summary:'Researchers find awe boosts wellbeing.'},
          {title:'How reading fiction quietly rewires empathy', url:'https://theconversation.com/global-fiction', date:new Date(Date.now()-3600e3*30).toISOString(), summary:''},
        ]};
      }
      return {ok:false, error:'未知 feed'};
    },
  }};
  window.dispatchEvent(new Event('pywebviewready'));
})();
